// Register new user
function register_new_user() {
    if (isset($_POST['register'])) {
        $username = sanitize_user($_POST['username']);
        $email = sanitize_email($_POST['email']);
        $password = $_POST['password'];

        if (!username_exists($username) && !email_exists($email)) {
            $user_id = wp_create_user($username, $password, $email);
            if (!is_wp_error($user_id)) {
                echo 'User registered successfully.';
            } else {
                echo 'Error in user registration.';
            }
        } else {
            echo 'Username or email already exists.';
        }
    }
}
add_action('init', 'register_new_user');

// Login user
function login_user() {
    if (isset($_POST['login'])) {
        $username = sanitize_user($_POST['username']);
        $password = $_POST['password'];

        $user = get_user_by('login', $username);
        if ($user && wp_check_password($password, $user->user_pass, $user->ID)) {
            wp_set_current_user($user->ID);
            wp_set_auth_cookie($user->ID);
            do_action('wp_login', $user->user_login);
            echo 'Login successful.';
        } else {
            echo 'Invalid username or password.';
        }
    }
}
add_action('init', 'login_user');

// Add registration form to a page
function add_registration_form() {
    ?>
    <form method="post">
        Username: <input type="text" name="username"><br>
        Email: <input type="email" name="email"><br>
        Password: <input type="password" name="password"><br>
        <input type="submit" name="register" value="Register">
    </form>
    <?php
}
add_shortcode('registration_form', 'add_registration_form');

